'use client';

import * as React from 'react';
import { motion, type HTMLMotionProps } from 'motion/react';

import { Slot, type WithAsChild } from '@/registry/ebonui/ui/slot';
import { cn } from '@/lib/utils';

type SlideButtonProps = WithAsChild<
  HTMLMotionProps<'button'> & {
    delay?: string;
    fillHeight?: string;
    hoverScale?: number;
    tapScale?: number;
  }
>;

function SlideButton({
  delay = '0.3s',
  fillHeight = '3px',
  hoverScale = 1.05,
  tapScale = 0.95,
  asChild = false,
  className,
  style,
  ...props
}: SlideButtonProps) {
  const Comp = asChild ? Slot : motion.button;

  return (
    <Comp
      data-slot="slide-button"
      whileTap={{ scale: tapScale }}
      whileHover={{
        scale: hoverScale,
        '--slide-button-fill-width': '100%',
        '--slide-button-fill-height': '100%',
        '--slide-button-delay': delay,
        transition: { duration: 0 },
      }}
      className={cn(
        'relative inline-flex items-center justify-center overflow-hidden rounded-md px-4 py-2 font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
        className
      )}
      style={
        {
          '--slide-button-fill-width': '-1%',
          '--slide-button-fill-height': fillHeight,
          '--slide-button-delay': '0s',
          '--slide-button-color': 'currentColor',
          '--slide-button-background-color': 'transparent',

          background:
            'linear-gradient(var(--slide-button-color) 0 0) no-repeat calc(200% - var(--slide-button-fill-width)) 100% / 200% var(--slide-button-fill-height)',
          backgroundColor: 'var(--slide-button-background-color)',

          transition: `
            background ${delay} var(--slide-button-delay),
            color ${delay} ${delay},
            background-position ${delay} calc(${delay} - var(--slide-button-delay))
          `,
          ...style,
        } as React.CSSProperties
      }
      {...props}
    />
  );
}

export { SlideButton, type SlideButtonProps };
